+        let new = make_test_ir(&["A", "B"], &[(0, 1)]);
+        let diff = diff_diagrams(&old, &new);
+        let config = MermaidConfig::default();
+        let layout = mermaid_layout_diagram(&new, &config);
+        // Very small area with removed items (legend needs space)
+        let area = Rect {
+            x: 0,
+            y: 0,
