+    #[test]
+    fn diff_edge_with_same_label_unchanged() {
+        let mut old = make_test_ir(&["A", "B"], &[(0, 1)]);
+        old.labels.push(IrLabel {
+            text: "same".to_string(),
+            span: make_test_span(),
+        });
+        old.edges[0].label = Some(IrLabelId(old.labels.len() - 1));
+
+        let mut new = make_test_ir(&["A", "B"], &[(0, 1)]);
+        new.labels.push(IrLabel {
+            text: "same".to_string(),
+            span: make_test_span(),
+        });
